using namespace std;
char a='A',b='A'-1;
int main(){
	int n;
	cin>>n;
	for(int i=0;i<n;i++){
		a=b;
		for(int i=0;i<n;i++){
			a++;
			if(a=='['){
							a='A';
						}
			cout<<a;
			
		}b++;
		if(b=='['){
			b='A';
		}
		cout<<endl;
	}return 0;
}
